import React, { useState, useEffect } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, Loader2, ShoppingCart } from 'lucide-react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 }; 

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [sugerencias, setSugerencias] = useState([]);
  const [distanciaReal, setDistanciaReal] = useState(0);
  const [cargando, setCargando] = useState(false);
  const [verCarrito, setVerCarrito] = useState(false); // Control para mostrar/ocultar carrito

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const agrupado = {};
    
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      if (ofs.length > 0) {
        agrupado[l.nombre] = ofs.map(o => ({ ...o, nombreLocal: l.nombre }));
      }
    });
    setOfertasPorLocal(agrupado);

    const historial = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    setPedidos(historial);
  }, []);

  const seleccionarDireccion = (item) => {
    const d = calcularDistanciaReal(parseFloat(item.lat), parseFloat(item.lon), COORDS_LOCAL.lat, COORDS_LOCAL.lon);
    setDistanciaReal(d);
    setBusqueda(`${item.address.road || ''} ${item.address.house_number || ''}, ${item.address.city || ''}`);
    setSugerencias([]);
  };

  const handlePago = (total) => {
    const nuevo = {
      id: `PED-${Date.now()}`,
      total,
      fecha: new Date().toLocaleString(),
      estado: 'proceso',
      distancia: distanciaReal,
      direccion: busqueda,
      items: [...cart]
    };
    const listaActualizada = [nuevo, ...pedidos];
    setPedidos(listaActualizada);
    localStorage.setItem('historial-pedidos', JSON.stringify(listaActualizada));
    setCart([]);
    setVerCarrito(false);
    setTab('proceso');
  };

  return (
    <div style={panelLayout}>
      {/* SIDEBAR */}
      <div style={sidebar}>
        <div style={{padding: '20px', textAlign: 'center'}}>
            <h2 style={{color: '#e67e22'}}>OFERTASAPP</h2>
        </div>
        <nav style={{display: 'flex', flexDirection: 'column', gap: '5px', padding: '10px'}}>
            <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? btnNavActive : btnNav}>
                <ShoppingBag size={20}/> Hacer mi pedido
            </button>
            <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? btnNavActive : btnNav}>
                <ShoppingCart size={20}/> Ver mi carrito ({cart.length})
            </button>
            <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? btnNavActive : btnNav}>
                <Clock size={20}/> En Proceso
            </button>
            <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? btnNavActive : btnNav}>
                <CheckCircle size={20}/> Historial
            </button>
        </nav>
      </div>

      {/* CONTENIDO */}
      <div style={mainContent}>
        {tab === 'tienda' && !verCarrito && (
          <>
            <div style={searchBar}>
              <MapPin size={20} color="#e67e22" />
              <input style={input} placeholder="¿A dónde enviamos hoy?" value={busqueda} onChange={(e) => {/* funcion buscar */}} />
            </div>

            {Object.keys(ofertasPorLocal).map(nombreLocal => (
              <div key={nombreLocal} style={localSection}>
                <h3 style={localTitle}>{nombreLocal}</h3>
                <div style={horizontalScroll}>
                  {ofertasPorLocal[nombreLocal].map(o => (
                    <div key={o.id} style={cardOferta}>
                      <img src={o.imagen} style={imgStyle} alt="" />
                      <div style={{padding: '12px'}}>
                        <h4 style={{margin: '0 0 8px 0', fontSize: '1rem'}}>{o.producto}</h4>
                        <button style={btnAdd} onClick={() => setCart([...cart, o])}>
                          Agregar ${o.precioNuevo}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </>
        )}

        {verCarrito && (
          <div style={carritoView}>
            <h2>Resumen de tu pedido</h2>
            <Carrito cart={cart} setCart={setCart} distanciaReal={distanciaReal} onCheckout={handlePago} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centeredContainer}>
            {pedidos.filter(p => p.estado === 'proceso').map(p => (
              <SeguimientoPedido key={p.id} pedido={p} onFinalizar={(id) => {/* funcion finalizar */}} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const panelLayout = { display: 'flex', minHeight: '100vh', background: '#f4f7f9' };
const sidebar = { width: '260px', background: '#1a202c', color: 'white', position: 'fixed', height: '100vh' };
const mainContent = { marginLeft: '260px', flex: 1, padding: '30px' };

const btnNav = { display: 'flex', alignItems: 'center', gap: '12px', padding: '15px', background: 'none', border: 'none', color: '#a0aec0', cursor: 'pointer', borderRadius: '10px', width: '100%', textAlign: 'left', transition: '0.2s', fontWeight: '500' };
const btnNavActive = { ...btnNav, background: '#e67e22', color: 'white' };

const localSection = { marginBottom: '40px' };
const localTitle = { fontSize: '1.4rem', color: '#2d3748', marginBottom: '15px', borderLeft: '5px solid #e67e22', paddingLeft: '15px' };
const horizontalScroll = { display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '15px' };

const cardOferta = { minWidth: '220px', background: 'white', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAdd = { width: '100%', padding: '10px', background: '#1a202c', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' };

const searchBar = { display: 'flex', alignItems: 'center', background: 'white', padding: '15px 25px', borderRadius: '12px', marginBottom: '30px', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px', fontSize: '1rem' };

const carritoView = { maxWidth: '600px', margin: '0 auto', background: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' };
const centeredContainer = { maxWidth: '700px', margin: '0 auto' };

export default PanelCliente;
